fn get_ffi_runtime() -> &'static tokio::runtime::Runtime {
    use std::sync::OnceLock;
    static RUNTIME: OnceLock<tokio::runtime::Runtime> = OnceLock::new();
    RUNTIME.get_or_init(|| tokio::runtime::Runtime::new().expect("Failed to create tokio runtime"))
}

/// Create a new LLM client with simple scalar configuration.
///
/// This is the primary binding entry-point. All parameters except `api_key`
/// are optional â omitting them uses the same defaults as
/// `ClientConfigBuilder`.
/// \note Returns `LiterLlmError` if the underlying HTTP client cannot be
/// constructed, or if the resolved provider configuration is invalid.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_create_client(
    api_key: *const std::ffi::c_char,
    base_url: *const std::ffi::c_char,
    timeout_secs: u64,
    max_retries: u32,
    model_hint: *const std::ffi::c_char,
) -> *mut liter_llm::client::DefaultClient {
    clear_last_error();
    if api_key.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'api_key'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees api_key is a valid pointer; string is valid UTF-8 from caller.
    let api_key_rs = match unsafe { CStr::from_ptr(api_key) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'api_key'");
            return std::ptr::null_mut();
        }
    };
    let base_url_rs = if base_url.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees base_url is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(base_url) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'base_url'");
                return std::ptr::null_mut();
            }
        }
    };
    // Optional numeric primitive: max value of type = None
    let timeout_secs_rs = if timeout_secs == u64::MAX {
        None
    } else {
        Some(timeout_secs)
    };
    // Optional numeric primitive: max value of type = None
    let max_retries_rs = if max_retries == u32::MAX {
        None
    } else {
        Some(max_retries)
    };
    let model_hint_rs = if model_hint.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees model_hint is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(model_hint) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'model_hint'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = liter_llm::create_client(api_key_rs, base_url_rs, timeout_secs_rs, max_retries_rs, model_hint_rs);
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

