/// Register a custom provider in the global runtime registry.
///
/// The provider will be checked **before** all built-in providers during model
/// detection. If a provider with the same `name` already exists it is replaced.
/// \note Returns an error if the config is invalid (empty name, empty base_url, or
/// no model prefixes).
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_register_custom_provider(
    config: *const liter_llm::provider::custom::CustomProviderConfig,
) -> i32 {
    clear_last_error();
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return -1;
    }
    // SAFETY: null check above guarantees config is a valid non-null pointer.
    let config_rs = unsafe { &*config }.clone();
    let result = liter_llm::provider::custom::register_custom_provider(config_rs);
    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(2, &e.to_string());
            -1
        }
    }
}

/// Remove a previously registered custom provider by name.
///
/// Returns `true` if a provider with the given name was found and removed,
/// `false` if no such provider existed.
/// \note Returns an error only if the internal lock is poisoned.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_unregister_custom_provider(name: *const std::ffi::c_char) -> i32 {
    clear_last_error();
    if name.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'name'");
        return 0;
    }
    // SAFETY: null check above guarantees name is a valid pointer; string is valid UTF-8 from caller.
    let name_rs = match unsafe { CStr::from_ptr(name) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'name'");
            return 0;
        }
    };
    let result = liter_llm::provider::custom::unregister_custom_provider(&name_rs);
    match result {
        Ok(val) => {
            if val {
                1
            } else {
                0
            }
        }
        Err(e) => {
            set_last_error(2, &e.to_string());
            0
        }
    }
}

/// Return the capability flags for a named provider.
///
/// Performs an O(n) linear scan over the embedded registry (143 entries).
/// Returns an owned value so that bindings can box/copy it across the FFI
/// boundary without dealing with lifetimes. `ProviderCapabilities` is `Copy`,
/// so this is a cheap memcpy of seven `bool` fields.
///
/// For unknown `provider_name` values the function returns an all-`false`
/// sentinel so callers never need to handle `Option`.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_capabilities(
    provider_name: *const std::ffi::c_char,
) -> *mut liter_llm::provider::ProviderCapabilities {
    clear_last_error();
    if provider_name.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'provider_name'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees provider_name is a valid pointer; string is valid UTF-8 from caller.
    let provider_name_rs = match unsafe { CStr::from_ptr(provider_name) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'provider_name'");
            return std::ptr::null_mut();
        }
    };
    let result = liter_llm::provider::capabilities(&provider_name_rs);
    Box::into_raw(Box::new(result))
}

/// Return all provider configs from the registry.
///
/// Useful for tooling, documentation generation, or runtime enumeration.
/// Returns the public `ProviderConfig` slice (without capability flags).
/// To query capability flags for a specific provider use `capabilities`.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_all_providers() -> *mut std::ffi::c_char {
    clear_last_error();
    let result = liter_llm::provider::all_providers();
    match result {
        Ok(val) => match serde_json::to_string(&val) {
            Ok(__alef_return) => match CString::new(__alef_return) {
                Ok(cs) => {
                    set_last_return_len(cs.as_bytes().len());
                    cs.into_raw()
                }
                Err(_) => {
                    set_last_return_len(0);
                    std::ptr::null_mut()
                }
            },
            Err(_) => {
                set_last_return_len(0);
                std::ptr::null_mut()
            }
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Return the byte length of the C string most recently returned by `literllm_all_providers` on this
/// thread. Returns 0 when the primary call returned null or failed before producing a string. Enables
/// safe slice construction in Zig and Java FFM Panama without a NUL-scan.
/// \note SAFETY: Pointer arguments are ignored and are present only to keep the companion ABI aligned
/// with `literllm_all_providers`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_all_providers_len() -> usize {
    last_return_len()
}

/// Return the set of complex provider names.
///
/// Complex providers require custom auth/routing logic beyond simple bearer
/// tokens (e.g. AWS Bedrock SigV4, Vertex AI OAuth2).
///
/// The returned reference points into the static registry â no allocation.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_complex_provider_names() -> *mut std::ffi::c_char {
    clear_last_error();
    let result = liter_llm::provider::complex_provider_names();
    match result {
        Ok(val) => match serde_json::to_string(&val) {
            Ok(__alef_return) => match CString::new(__alef_return) {
                Ok(cs) => {
                    set_last_return_len(cs.as_bytes().len());
                    cs.into_raw()
                }
                Err(_) => {
                    set_last_return_len(0);
                    std::ptr::null_mut()
                }
            },
            Err(_) => {
                set_last_return_len(0);
                std::ptr::null_mut()
            }
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Return the byte length of the C string most recently returned by `literllm_complex_provider_names`
/// on this thread. Returns 0 when the primary call returned null or failed before producing a string.
/// Enables safe slice construction in Zig and Java FFM Panama without a NUL-scan.
/// \note SAFETY: Pointer arguments are ignored and are present only to keep the companion ABI aligned
/// with `literllm_complex_provider_names`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_complex_provider_names_len() -> usize {
    last_return_len()
}

/// Calculate the estimated cost of a completion given a model name and token
/// counts.
///
/// Returns `None` if the model is not present in the embedded pricing registry.
/// Returns `Some(cost_usd)` otherwise, where the value is in US dollars.
///
/// When an exact model name match is not found, progressively shorter prefixes
/// are tried by stripping from the last `-` or `.` separator.  For example,
/// `gpt-4-0613` will match `gpt-4` if no `gpt-4-0613` entry exists.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
/// \code
/// use liter_llm::cost;
///
/// let usd = cost::completion_cost("gpt-4o", 1_000, 500).expect("gpt-4o is a known model");
/// // 1000 * 0.0000025 + 500 * 0.00001 = 0.0025 + 0.005 = 0.0075
/// assert!((usd - 0.0075).abs() < 1e-9);
/// \endcode
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_completion_cost(
    model: *const std::ffi::c_char,
    prompt_tokens: u64,
    completion_tokens: u64,
) -> f64 {
    clear_last_error();
    if model.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'model'");
        return 0.0;
    }
    // SAFETY: null check above guarantees model is a valid pointer; string is valid UTF-8 from caller.
    let model_rs = match unsafe { CStr::from_ptr(model) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'model'");
            return 0.0;
        }
    };
    let prompt_tokens_rs = prompt_tokens;
    let completion_tokens_rs = completion_tokens;
    let result = liter_llm::completion_cost(&model_rs, prompt_tokens_rs, completion_tokens_rs);
    result.unwrap_or(0.0)
}

/// Calculate the estimated cost of a completion, accounting for cached
/// (cache-hit) prompt tokens billed at the provider's discounted rate.
///
/// `cached_tokens` is the count of prompt tokens served from the provider's
/// prompt cache. It must be `<= prompt_tokens` (cached tokens are a subset of
/// the prompt). The non-cached portion is billed at `input_cost_per_token`
/// and the cached portion at `cache_read_input_token_cost` when the model
/// has cache pricing; otherwise the entire prompt is billed at the regular
/// input rate.
///
/// Returns `None` if the model is not present in the embedded pricing
/// registry, mirroring `completion_cost`.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_completion_cost_with_cache(
    model: *const std::ffi::c_char,
    prompt_tokens: u64,
    cached_tokens: u64,
    completion_tokens: u64,
) -> f64 {
    clear_last_error();
    if model.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'model'");
        return 0.0;
    }
    // SAFETY: null check above guarantees model is a valid pointer; string is valid UTF-8 from caller.
    let model_rs = match unsafe { CStr::from_ptr(model) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'model'");
            return 0.0;
        }
    };
    let prompt_tokens_rs = prompt_tokens;
    let cached_tokens_rs = cached_tokens;
    let completion_tokens_rs = completion_tokens;
    let result =
        liter_llm::completion_cost_with_cache(&model_rs, prompt_tokens_rs, cached_tokens_rs, completion_tokens_rs);
    result.unwrap_or(0.0)
}

