#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_clear() {
    clear_last_error();
    let result = liter_llm::guardrail::registry::clear();
}

/// Count tokens in a text string using the tokenizer for the given model.
///
/// The tokenizer is resolved from the model name prefix (e.g. `"gpt-4o"` maps
/// to the `Xenova/gpt-4o` HuggingFace tokenizer). Tokenizers are cached after
/// first load.
/// \note Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded
/// (e.g. network failure on first use) or if tokenization itself fails.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_count_tokens(model: *const std::ffi::c_char, text: *const std::ffi::c_char) -> usize {
    clear_last_error();
    if model.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'model'");
        return 0;
    }
    // SAFETY: null check above guarantees model is a valid pointer; string is valid UTF-8 from caller.
    let model_rs = match unsafe { CStr::from_ptr(model) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'model'");
            return 0;
        }
    };
    if text.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'text'");
        return 0;
    }
    // SAFETY: null check above guarantees text is a valid pointer; string is valid UTF-8 from caller.
    let text_rs = match unsafe { CStr::from_ptr(text) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'text'");
            return 0;
        }
    };
    let result = liter_llm::count_tokens(&model_rs, &text_rs);
    match result {
        Ok(val) => val,
        Err(e) => {
            set_last_error(2, &e.to_string());
            0
        }
    }
}

/// Count tokens for a full `ChatCompletionRequest`.
///
/// Sums tokens across all message text contents plus a per-message overhead
/// of ~4 tokens (for role, separators, and formatting metadata). Tool
/// definitions and multimodal content parts (images, audio, documents) are
/// not counted â only textual content contributes to the token total.
/// \note Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded or
/// if tokenization fails for any message.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_count_request_tokens(
    model: *const std::ffi::c_char,
    req: *const liter_llm::types::ChatCompletionRequest,
) -> usize {
    clear_last_error();
    if model.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'model'");
        return 0;
    }
    // SAFETY: null check above guarantees model is a valid pointer; string is valid UTF-8 from caller.
    let model_rs = match unsafe { CStr::from_ptr(model) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'model'");
            return 0;
        }
    };
    if req.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'req'");
        return 0;
    }
    // SAFETY: null check above guarantees req is a valid non-null pointer.
    let req_rs = unsafe { &*req };
    let result = liter_llm::count_request_tokens(&model_rs, &req_rs);
    match result {
        Ok(val) => val,
        Err(e) => {
            set_last_error(2, &e.to_string());
            0
        }
    }
}

/// Assert that `current_len + incoming` does not exceed `limit`.
///
/// Call this before appending `incoming` bytes to any buffer that must
/// stay below `limit`.  Returns `Err(LiterLlmError::Streaming)` on overflow
/// and emits a `tracing::warn!` with context.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
/// \code
/// check_bound("SSE buffer", buffer.len(), chunk.len(), SSE_BUFFER_MAX_BYTES)?;
/// buffer.push_str(chunk_str);
/// \endcode
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_check_bound(
    context: *const std::ffi::c_char,
    current_len: usize,
    incoming: usize,
    limit: usize,
) -> i32 {
    clear_last_error();
    if context.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'context'");
        return -1;
    }
    // SAFETY: null check above guarantees context is a valid pointer; string is valid UTF-8 from caller.
    let context_rs = match unsafe { CStr::from_ptr(context) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'context'");
            return -1;
        }
    };
    let current_len_rs = current_len;
    let incoming_rs = incoming;
    let limit_rs = limit;
    let result = liter_llm::util::bounds::check_bound(&context_rs, current_len_rs, incoming_rs, limit_rs);
    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(2, &e.to_string());
            -1
        }
    }
}

/// Install the `ring` crypto provider as the rustls process default, idempotently.
///
/// rustls 0.23+ removed the implicit default provider. This function installs
/// `ring` once per process. Subsequent calls are no-ops. Calling it from a
/// downstream Rust app that has already installed `aws-lc-rs` is safe â the
/// `Err` from `install_default()` is silently ignored.
///
/// Called automatically by every internal `reqwest::Client` constructor
/// (auth providers, default HTTP client). Bindings and downstream consumers
/// reach those constructors transitively, so no manual init is required.
///
/// WASM builds are exempt â the WASM target uses the browser/Node.js fetch
/// API instead of rustls, so no crypto provider is needed.
///
/// Windows builds use native-tls (SChannel) via reqwest, so rustls is not
/// present and no crypto provider installation is needed.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(all(feature = "native-http", not(target_os = "windows")))]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn literllm_ensure_crypto_provider() {
    clear_last_error();
    let result = liter_llm::ensure_crypto_provider();
}

/// Return the HTTP status code for the error pointed to by `err`.
/// Returns `0` if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn literllm_liter_llm_error_status_code(err: *const liter_llm::error::LiterLlmError) -> u16 {
    // SAFETY: caller guarantees `err` points to a live `liter_llm::error::LiterLlmError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return 0;
    }
    (*err).status_code()
}

/// Return whether the error pointed to by `err` is transient.
/// Returns `false` if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn literllm_liter_llm_error_is_transient(err: *const liter_llm::error::LiterLlmError) -> bool {
    // SAFETY: caller guarantees `err` points to a live `liter_llm::error::LiterLlmError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return false;
    }
    (*err).is_transient()
}

/// Return the machine-readable error category string for the error pointed
/// to by `err` as a heap-allocated, NUL-terminated C string.
/// The caller must free the returned pointer with `literllm_liter_llm_error_error_type_free`.
/// Returns a null pointer if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn literllm_liter_llm_error_error_type(
    err: *const liter_llm::error::LiterLlmError,
) -> *mut std::ffi::c_char {
    // SAFETY: caller guarantees `err` points to a live `liter_llm::error::LiterLlmError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return std::ptr::null_mut();
    }
    let s = (*err).error_type();
    // SAFETY: `error_type()` returns a `'static str` containing no NUL bytes.
    std::ffi::CString::new(s)
        .map(|c| c.into_raw())
        .unwrap_or(std::ptr::null_mut())
}

/// Free a string previously returned by `literllm_liter_llm_error_error_type`.
/// Passing a null pointer is a no-op.
#[no_mangle]
pub unsafe extern "C" fn literllm_liter_llm_error_error_type_free(ptr: *mut std::ffi::c_char) {
    // SAFETY: `ptr` was allocated by `CString::into_raw` inside
    // `literllm_liter_llm_error_error_type` and is now being reclaimed by the matching
    // `CString::from_raw`.  Passing null is explicitly allowed.
    if !ptr.is_null() {
        drop(std::ffi::CString::from_raw(ptr));
    }
}
